# JavaScript Rate Limiter

Here are a few implementations depending on your needs.

## 1. Simple Rate Limiter (Sliding Window)

Limits a function to at most N calls per second by tracking call timestamps.

```javascript
function rateLimit(fn, maxCallsPerSecond) {
  const timestamps = [];

  return async function (...args) {
    const now = Date.now();

    // Remove timestamps older than 1 second
    while (timestamps.length > 0 && now - timestamps[0] >= 1000) {
      timestamps.shift();
    }

    if (timestamps.length >= maxCallsPerSecond) {
      // Wait until the oldest call falls outside the 1s window
      const waitTime = 1000 - (now - timestamps[0]);
      await new Promise((resolve) => setTimeout(resolve, waitTime));
      return rateLimit(fn, maxCallsPerSecond).apply(this, args);
    }

    timestamps.push(Date.now());
    return fn.apply(this, args);
  };
}
```

## 2. Queue-Based Rate Limiter (Recommended)

This version queues calls and processes them at a steady rate, preserving order and never dropping requests.

```javascript
class RateLimiter {
  /**
   * @param {number} maxPerSecond - Max calls allowed per second
   */
  constructor(maxPerSecond) {
    this.maxPerSecond = maxPerSecond;
    this.queue = [];
    this.timestamps = [];
    this.processing = false;
  }

  /**
   * Wraps an async function so it respects the rate limit.
   */
  wrap(fn) {
    return (...args) => this.schedule(() => fn(...args));
  }

  /**
   * Schedules a task and returns a promise that resolves with its result.
   */
  schedule(task) {
    return new Promise((resolve, reject) => {
      this.queue.push({ task, resolve, reject });
      this._process();
    });
  }

  async _process() {
    if (this.processing) return;
    this.processing = true;

    while (this.queue.length > 0) {
      const now = Date.now();

      // Drop timestamps older than 1 second
      this.timestamps = this.timestamps.filter((t) => now - t < 1000);

      if (this.timestamps.length >= this.maxPerSecond) {
        // Wait until a slot frees up
        const waitTime = 1000 - (now - this.timestamps[0]);
        await delay(waitTime);
        continue;
      }

      const { task, resolve, reject } = this.queue.shift();
      this.timestamps.push(Date.now());

      // Run task without blocking the loop (fire and handle)
      Promise.resolve()
        .then(task)
        .then(resolve)
        .catch(reject);
    }

    this.processing = false;
  }
}

function delay(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}
```

### Usage

```javascript
// Example async function
async function fetchData(id) {
  console.log(`Fetching ${id} at ${new Date().toISOString()}`);
  return id * 2;
}

// Allow at most 3 calls per second
const limiter = new RateLimiter(3);
const limitedFetch = limiter.wrap(fetchData);

// Fire 10 calls — they'll execute at most 3 per second
async function run() {
  const results = await Promise.all(
    Array.from({ length: 10 }, (_, i) => limitedFetch(i))
  );
  console.log("Results:", results);
}

run();
```

## 3. Token Bucket Variant

Allows bursts up to N but refills tokens over time — great for smoother throttling.

```javascript
class TokenBucketLimiter {
  constructor(maxPerSecond) {
    this.capacity = maxPerSecond;
    this.tokens = maxPerSecond;
    this.refillRate = maxPerSecond; // tokens per second
    this.lastRefill = Date.now();
    this.queue = [];
  }

  _refill() {
    const now = Date.now();
    const elapsed = (now - this.lastRefill) / 1000;
    this.tokens = Math.min(this.capacity, this.tokens + elapsed * this.refillRate);
    this.lastRefill = now;
  }

  wrap(fn) {
    return (...args) => this.schedule(() => fn(...args));
  }

  schedule(task) {
    return new Promise((resolve, reject) => {
      this.queue.push({ task, resolve, reject });
      this._drain();
    });
  }

  async _drain() {
    if (this._draining) return;
    this._draining = true;

    while (this.queue.length > 0) {
      this._refill();

      if (this.tokens >= 1) {
        this.tokens -= 1;
        const { task, resolve, reject } = this.queue.shift();
        Promise.resolve().then(task).then(resolve).catch(reject);
      } else {
        const waitTime = ((1 - this.tokens) / this.refillRate) * 1000;
        await new Promise((r) => setTimeout(r, waitTime));
      }
    }

    this._draining = false;
  }
}
```

## Comparison

| Approach | Behavior | Best For |
|----------|----------|----------|
| **Sliding window** | Strict N per rolling second | Simple cases |
| **Queue-based** | Steady throttling, preserves order, no drops | API clients, scrapers |
| **Token bucket** | Allows bursts, then smooths out | APIs with burst tolerance |

**Recommendation:** Use the **queue-based `RateLimiter`** (option 2) for most cases — it never drops calls, returns proper promises, and handles errors correctly.

